public class GsonToJsonTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void testToJson_withNullSrcAndNullType() {
    String json = gson.toJson(null, (Type) null);
    assertEquals("null", json);
  }

  @Test
  public void testToJson_withPrimitiveType() {
    String json = gson.toJson(123, Integer.class);
    assertEquals("123", json);
  }

  @Test
  public void testToJson_withStringType() {
    String json = gson.toJson("test", String.class);
    assertEquals("\"test\"", json);
  }

  @Test
  public void testToJson_withComplexObject() {
    TestClass obj = new TestClass();
    obj.id = 1;
    obj.name = "abc";
    String json = gson.toJson(obj, TestClass.class);
    assertTrue(json.contains("\"id\":1"));
    assertTrue(json.contains("\"name\":\"abc\""));
  }

  @Test
  public void testToJson_invokesPrivateToJsonMethod() throws Exception {
    StringWriter writer = new StringWriter();
    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", Object.class, Type.class, java.lang.Appendable.class);
    toJsonMethod.setAccessible(true);

    TestClass obj = new TestClass();
    obj.id = 42;
    obj.name = "reflection";

    toJsonMethod.invoke(gson, obj, TestClass.class, writer);

    String json = writer.toString();
    assertTrue(json.contains("\"id\":42"));
    assertTrue(json.contains("\"name\":\"reflection\""));
  }

  static class TestClass {
    int id;
    String name;
  }
}
